  // ============================================================
  // PROCESS SECTION
  // ============================================================
  "process.title": { en: "How We Get It Done", es: "As\u00ED Lo Hacemos", fr: "Comment On Fait" },
  "process.subtitle": {
    en: "No fluff, no mystery. Here is exactly how we take you from idea to results.",
    es: "Sin rodeos, sin misterio. As\u00ED es exactamente c\u00F3mo te llevamos de la idea a los resultados.",
    fr: "Pas de blabla, pas de myst\u00E8re. Voici exactement comment on vous am\u00E8ne de l\u2019id\u00E9e aux r\u00E9sultats.",
  },
  "process.step1.title": { en: "Discovery", es: "Descubrimiento", fr: "D\u00E9couverte" },
  "process.step1.desc": {
    en: "We look at everything you have going on, check out the competition, and find where you are leaving money on the table.",
    es: "Miramos todo lo que tienes, checamos a la competencia y encontramos d\u00F3nde est\u00E1s dejando dinero en la mesa.",
    fr: "On regarde tout ce que vous avez en place, on \u00E9tudie la concurrence et on trouve o\u00F9 vous laissez de l\u2019argent sur la table.",
  },
  "process.step2.title": { en: "Strategy", es: "Estrategia", fr: "Strat\u00E9gie" },
  "process.step2.desc": {
    en: "We build a game plan with real numbers, real deadlines, and real deliverables. No vague promises.",
    es: "Armamos un plan de juego con n\u00FAmeros reales, fechas reales y entregables reales. Sin promesas vagas.",
    fr: "On construit un plan de jeu avec de vrais chiffres, de vraies \u00E9ch\u00E9ances et de vrais livrables. Pas de promesses vagues.",
  },
  "process.step3.title": { en: "Execution", es: "Ejecuci\u00F3n", fr: "Ex\u00E9cution" },
  "process.step3.desc": {
    en: "We get to work. AI helps us move fast, but humans make sure everything is on point.",
    es: "Nos ponemos a trabajar. La IA nos ayuda a movernos r\u00E1pido, pero los humanos nos aseguramos de que todo est\u00E9 perfecto.",
    fr: "On se met au travail. L\u2019IA nous aide \u00E0 aller vite, mais les humains s\u2019assurent que tout est au point.",
  },
  "process.step4.title": { en: "Optimization", es: "Optimizaci\u00F3n", fr: "Optimisation" },
  "process.step4.desc": {
    en: "We watch the data, kill what is not working, and double down on what is. Rinse and repeat.",
    es: "Miramos los datos, matamos lo que no funciona y le metemos m\u00E1s a lo que s\u00ED. Repetir.",
    fr: "On surveille les donn\u00E9es, on arr\u00EAte ce qui ne marche pas et on double la mise sur ce qui marche. On r\u00E9p\u00E8te.",
  },

  // Process page-specific keys (more detailed than homepage section)
  "process.badge": { en: "Our Process", es: "Nuestro Proceso", fr: "Notre processus" },
  "process.heading": { en: "A Proven System for Measurable Growth", es: "Un Sistema Comprobado para Crecimiento Medible", fr: "Un syst\u00e8me \u00e9prouv\u00e9 pour une croissance mesurable" },
  "process.description": { en: "Every project follows the same proven framework. We move fast, stay aligned with your goals, and deliver results you can actually measure.", es: "Cada proyecto sigue un marco estructurado dise\u00f1ado para moverse r\u00e1pido, mantenerse alineado y entregar resultados que puedas medir.", fr: "Chaque engagement suit un cadre structur\u00e9 con\u00e7u pour avancer vite, rester align\u00e9 et produire des r\u00e9sultats mesurables." },
  "process.page.step1.title": { en: "Discovery & Audit", es: "Descubrimiento y Auditor\u00eda", fr: "D\u00e9couverte et audit" },
  "process.page.step1.summary": { en: "We start by understanding your business, audience, and current marketing landscape.", es: "Comenzamos entendiendo su negocio, audiencia y panorama de marketing actual.", fr: "Nous commen\u00e7ons par comprendre votre entreprise, votre audience et votre paysage marketing actuel." },
  "process.page.step1.d1": { en: "Full digital presence audit across all channels", es: "Auditor\u00eda completa de presencia digital en todos los canales", fr: "Audit complet de la pr\u00e9sence num\u00e9rique sur tous les canaux" },
  "process.page.step1.d2": { en: "Competitor analysis and market positioning review", es: "An\u00e1lisis de competidores y revisi\u00f3n de posicionamiento de mercado", fr: "Analyse concurrentielle et revue du positionnement march\u00e9" },
  "process.page.step1.d3": { en: "Stakeholder interviews and goal alignment", es: "Entrevistas con stakeholders y alineaci\u00f3n de objetivos", fr: "Entretiens avec les parties prenantes et alignement des objectifs" },
  "process.page.step2.title": { en: "Strategy & Roadmap", es: "Estrategia y Hoja de Ruta", fr: "Strat\u00e9gie et feuille de route" },
  "process.page.step2.summary": { en: "We build a custom plan with clear priorities, timelines, and measurable KPIs.", es: "Construimos un plan personalizado con prioridades claras, plazos y KPIs medibles.", fr: "Nous \u00e9laborons un plan personnalis\u00e9 avec des priorit\u00e9s claires, des \u00e9ch\u00e9anciers et des KPI mesurables." },
  "process.page.step2.d1": { en: "Channel strategy and budget allocation", es: "Estrategia de canales y asignaci\u00f3n de presupuesto", fr: "Strat\u00e9gie de canaux et allocation de budget" },
  "process.page.step2.d2": { en: "Content calendar and campaign planning", es: "Calendario de contenido y planificaci\u00f3n de campa\u00f1as", fr: "Calendrier de contenu et planification de campagnes" },
  "process.page.step2.d3": { en: "KPI framework and reporting structure", es: "Marco de KPIs y estructura de reportes", fr: "Cadre de KPI et structure de rapports" },
  "process.page.step3.title": { en: "Execution & Launch", es: "Ejecuci\u00f3n y Lanzamiento", fr: "Ex\u00e9cution et lancement" },
  "process.page.step3.summary": { en: "We execute with AI-powered tools for speed, precision, and consistent quality.", es: "Ejecutamos con herramientas impulsadas por IA para velocidad, precisi\u00f3n y calidad consistente.", fr: "Nous ex\u00e9cutons avec des outils propuls\u00e9s par l\u2019IA pour la rapidit\u00e9, la pr\u00e9cision et une qualit\u00e9 constante." },
