  "studio.pkg3.desc": { en: "End-to-end production for brands and businesses that want premium content.", es: "Producci\u00f3n integral para marcas y negocios que desean contenido premium.", fr: "Production de bout en bout pour les marques et entreprises qui veulent du contenu premium." },
