  "studio.pkg3.i4": { en: "Full post-production editing", es: "Edici\u00f3n de postproducci\u00f3n completa", fr: "\u00c9dition de post-production compl\u00e8te" },
  "studio.pkg3.i5": { en: "Branded graphics and animations", es: "Gr\u00e1ficos y animaciones de marca", fr: "Graphiques et animations de marque" },
