  "careers.role.performance.desc": { en: "Paid media, SEO, email marketing, and analytics-driven campaign management.", es: "Medios pagados, SEO, email marketing y gesti\u00f3n de campa\u00f1as basada en an\u00e1lisis.", fr: "M\u00e9dias payants, SEO, marketing par courriel et gestion de campagnes bas\u00e9e sur les donn\u00e9es." },
  "careers.role.creative": { en: "Creative & Design", es: "Creatividad y Dise\u00f1o", fr: "Cr\u00e9ation et design" },
  "careers.role.creative.desc": { en: "Brand design, web development, copywriting, and visual content production.", es: "Dise\u00f1o de marca, desarrollo web, redacci\u00f3n y producci\u00f3n de contenido visual.", fr: "Design de marque, d\u00e9veloppement web, r\u00e9daction et production de contenu visuel." },
  "careers.role.production": { en: "Content Production", es: "Producci\u00f3n de Contenido", fr: "Production de contenu" },
  "careers.role.production.desc": { en: "Video editing, podcast production, photography, and social media content creation.", es: "Edici\u00f3n de video, producci\u00f3n de podcasts, fotograf\u00eda y creaci\u00f3n de contenido para redes sociales.", fr: "\u00c9dition vid\u00e9o, production de podcasts, photographie et cr\u00e9ation de contenu pour les r\u00e9seaux sociaux." },
  "careers.role.operations": { en: "Operations & AI", es: "Operaciones e IA", fr: "Op\u00e9rations et IA" },
  "careers.role.operations.desc": { en: "Workflow automation, AI tool development, system integrations, and internal process optimization.", es: "Automatizaci\u00f3n de flujos de trabajo, desarrollo de herramientas de IA, integraciones de sistemas y optimizaci\u00f3n de procesos internos.", fr: "Automatisation des flux de travail, d\u00e9veloppement d\u2019outils IA, int\u00e9grations de syst\u00e8mes et optimisation des processus internes." },
  "careers.expectations": { en: "What We Expect", es: "Lo que Esperamos", fr: "Ce que nous attendons" },
