  "careers.exp2": { en: "Comfort with AI tools and willingness to learn new systems", es: "Comodidad con herramientas de IA y disposici\u00f3n para aprender nuevos sistemas", fr: "Aisance avec les outils IA et volont\u00e9 d\u2019apprendre de nouveaux syst\u00e8mes" },
  "careers.exp3": { en: "Clear communication and consistent delivery on commitments", es: "Comunicaci\u00f3n clara y cumplimiento consistente de compromisos", fr: "Communication claire et respect constant des engagements" },
  "careers.exp4": { en: "A growth mindset and genuine interest in marketing and technology", es: "Mentalidad de crecimiento e inter\u00e9s genuino en marketing y tecnolog\u00eda", fr: "Un \u00e9tat d\u2019esprit de croissance et un int\u00e9r\u00eat sinc\u00e8re pour le marketing et la technologie" },
  "careers.cta.title": { en: "Interested in Working With Us?", es: "\u00bfInteresado en Trabajar con Nosotros?", fr: "Int\u00e9ress\u00e9 \u00e0 travailler avec nous\u00a0?" },
