  "resources.lt3": { en: "Email Marketing Mastery: Automation that converts", es: "Dominio del Email Marketing: Automatizaci\u00f3n que convierte", fr: "Ma\u00eetrise du marketing par courriel\u00a0: Automatisation qui convertit" },
