  "sd.web.t3.f3": { en: "Multi-team workflow support", es: "Soporte de flujos multi-equipo", fr: "Support de flux de travail multi-\u00e9quipe" },
  "sd.web.t3.f4": { en: "Ongoing optimization retainers", es: "Retainers de optimizaci\u00f3n continua", fr: "Mandats d\u2019optimisation continue" },
  "sd.web.t3.f5": { en: "Priority support structure", es: "Estructura de soporte prioritario", fr: "Structure de support prioritaire" },
  "sd.web.faq1.q": { en: "How long does a website project usually take?", es: "\u00bfCu\u00e1nto tiempo suele tomar un proyecto web?", fr: "Combien de temps dure un projet de site web\u00a0?" },
  "sd.web.faq1.a": { en: "Most standard projects run between 4-10 weeks depending on page count, content readiness, and integration complexity.", es: "La mayor\u00eda de los proyectos toman entre 4-10 semanas seg\u00fan p\u00e1ginas, contenido e integraciones.", fr: "La plupart des projets prennent entre 4 et 10 semaines selon les pages, le contenu et les int\u00e9grations." },
  "sd.web.faq2.q": { en: "Can my team edit content after launch?", es: "\u00bfPuede mi equipo editar contenido despu\u00e9s del lanzamiento?", fr: "Mon \u00e9quipe peut-elle modifier le contenu apr\u00e8s le lancement\u00a0?" },
  "sd.web.faq2.a": { en: "Yes. We set up a manageable CMS structure and provide guidance so your team can make updates confidently.", es: "S\u00ed. Configuramos un CMS manejable y damos orientaci\u00f3n para que tu equipo actualice con confianza.", fr: "Oui. Nous mettons en place un CMS g\u00e9rable et guidons votre \u00e9quipe pour des mises \u00e0 jour en toute confiance." },
  "sd.web.faq3.q": { en: "Do you support hosting and maintenance too?", es: "\u00bfTambi\u00e9n ofrecen hosting y mantenimiento?", fr: "Proposez-vous l\u2019h\u00e9bergement et la maintenance\u00a0?" },
  "sd.web.faq3.a": { en: "Yes. We can guide hosting setup and offer maintenance support for security, updates, and ongoing improvements.", es: "S\u00ed. Podemos guiar la configuraci\u00f3n de hosting y ofrecer mantenimiento para seguridad y mejoras.", fr: "Oui. Nous guidons la configuration d\u2019h\u00e9bergement et offrons un support de maintenance pour la s\u00e9curit\u00e9 et les am\u00e9liorations." },
  "sd.web.faq4.q": { en: "Can this be paired with SEO and paid ads?", es: "\u00bfSe puede combinar con SEO y anuncios pagados?", fr: "Peut-on combiner avec le SEO et la publicit\u00e9 payante\u00a0?" },
  "sd.web.faq4.a": { en: "Absolutely. We frequently pair web builds with SEO and ad campaigns to improve both traffic and conversions.", es: "Por supuesto. Combinamos desarrollo web con SEO y anuncios para mejorar tr\u00e1fico y conversiones.", fr: "Absolument. Nous combinons le d\u00e9veloppement web avec le SEO et les campagnes publicitaires pour am\u00e9liorer trafic et conversions." },

