  "sd.seo.t3.f4": { en: "Priority implementation support", es: "Soporte de implementaci\u00f3n prioritario", fr: "Support d\u2019impl\u00e9mentation prioritaire" },
  "sd.seo.faq1.q": { en: "How soon should we expect SEO results?", es: "\u00bfCu\u00e1n pronto debemos esperar resultados SEO?", fr: "Quand peut-on s\u2019attendre \u00e0 des r\u00e9sultats SEO\u00a0?" },
  "sd.seo.faq1.a": { en: "Most businesses see early movement in 2-3 months, with stronger compounding gains between months 4-6 and beyond.", es: "La mayor\u00eda ven movimiento en 2-3 meses, con ganancias compuestas m\u00e1s fuertes entre los meses 4-6.", fr: "La plupart voient des premiers mouvements en 2-3 mois, avec des gains compos\u00e9s plus forts entre les mois 4-6." },
  "sd.seo.faq2.q": { en: "Do you handle local SEO and business listings?", es: "¿Manejan SEO local y listados de negocios?", fr: "Gérez-vous le SEO local et les fiches d'entreprise\u00a0?" },
  "sd.seo.faq2.a": { en: "Yes. Local SEO is a core part of our process. We optimize your Google Business Profile, Yelp, Apple Maps, Bing Places, and other relevant directories to make sure you show up everywhere your customers are searching.", es: "Sí. El SEO local es central en nuestro proceso. Optimizamos tu Google Business Profile, Yelp, Apple Maps, Bing Places y otros directorios relevantes para asegurarnos de que aparezcas en todos los lugares donde tus clientes buscan.", fr: "Oui. Le SEO local est au cœur de notre processus. Nous optimisons votre Google Business Profile, Yelp, Apple Maps, Bing Places et autres annuaires pertinents pour que vous apparaissiez partout où vos clients cherchent." },
  "sd.seo.faq3.q": { en: "Can SEO work alongside paid ads?", es: "\u00bfPuede el SEO funcionar junto con anuncios pagados?", fr: "Le SEO peut-il fonctionner avec la publicit\u00e9 payante\u00a0?" },
  "sd.seo.faq3.a": { en: "Yes. Paid ads can capture short-term demand while SEO builds long-term visibility and lower-cost acquisition.", es: "S\u00ed. Los anuncios capturan demanda a corto plazo mientras el SEO construye visibilidad a largo plazo.", fr: "Oui. La publicit\u00e9 payante capture la demande court terme tandis que le SEO construit une visibilit\u00e9 long terme." },
  "sd.seo.faq4.q": { en: "Do you provide SEO content strategy too?", es: "\u00bfTambi\u00e9n proporcionan estrategia de contenido SEO?", fr: "Fournissez-vous aussi une strat\u00e9gie de contenu SEO\u00a0?" },
  "sd.seo.faq4.a": { en: "Yes. We provide content mapping, briefs, and page optimization guidance tied to intent and business goals.", es: "S\u00ed. Proporcionamos mapeo de contenido, briefs y optimizaci\u00f3n vinculados a intenci\u00f3n y objetivos.", fr: "Oui. Nous fournissons cartographie de contenu, briefs et optimisation li\u00e9s \u00e0 l\u2019intention et aux objectifs." },

