  "sd.ads.t3.f1": { en: "Cross-platform campaign management", es: "Gesti\u00f3n de campa\u00f1as multiplataforma", fr: "Gestion de campagnes multi-plateformes" },
  "sd.ads.t3.f2": { en: "Advanced attribution support", es: "Soporte de atribuci\u00f3n avanzada", fr: "Support d\u2019attribution avanc\u00e9" },
  "sd.ads.t3.f3": { en: "Performance dashboards", es: "Dashboards de rendimiento", fr: "Tableaux de bord de performance" },
  "sd.ads.t3.f4": { en: "Priority growth support", es: "Soporte prioritario de crecimiento", fr: "Support de croissance prioritaire" },
  "sd.ads.faq1.q": { en: "Which ad platforms do you support?", es: "\u00bfQu\u00e9 plataformas de anuncios soportan?", fr: "Quelles plateformes publicitaires supportez-vous\u00a0?" },
  "sd.ads.faq1.a": { en: "We manage Google Ads, Meta Ads (Facebook and Instagram), TikTok Ads, and LinkedIn Ads. We recommend platforms based on where your audience is most likely to convert.", es: "Gestionamos Google Ads, Meta Ads (Facebook e Instagram), TikTok Ads y LinkedIn Ads. Recomendamos plataformas según dónde es más probable que tu audiencia convierta.", fr: "Nous gérons Google Ads, Meta Ads (Facebook et Instagram), TikTok Ads et LinkedIn Ads. Nous recommandons les plateformes selon l'endroit où votre audience est la plus susceptible de convertir." },
  "sd.ads.faq2.q": { en: "Is media spend included in your management fee?", es: "\u00bfEl gasto en medios est\u00e1 incluido en la tarifa de gesti\u00f3n?", fr: "Les d\u00e9penses m\u00e9dia sont-elles incluses dans les frais de gestion\u00a0?" },
  "sd.ads.faq2.a": { en: "No. Ad spend is paid directly from your ad accounts. Our fee covers strategy, execution, and optimization.", es: "No. El gasto en anuncios se paga directamente desde tus cuentas. Nuestra tarifa cubre estrategia, ejecuci\u00f3n y optimizaci\u00f3n.", fr: "Non. Les d\u00e9penses publicitaires sont pay\u00e9es directement depuis vos comptes. Nos frais couvrent strat\u00e9gie, ex\u00e9cution et optimisation." },
  "sd.ads.faq3.q": { en: "How quickly can we launch campaigns?", es: "\u00bfQu\u00e9 tan r\u00e1pido podemos lanzar campa\u00f1as?", fr: "\u00c0 quelle vitesse pouvons-nous lancer des campagnes\u00a0?" },
  "sd.ads.faq3.a": { en: "Most campaigns can launch in 1-3 weeks depending on creative readiness, offer clarity, and tracking requirements.", es: "La mayor\u00eda de las campa\u00f1as pueden lanzarse en 1-3 semanas seg\u00fan los creativos, la oferta y el seguimiento.", fr: "La plupart des campagnes peuvent \u00eatre lanc\u00e9es en 1-3 semaines selon les cr\u00e9atifs, l\u2019offre et le suivi." },
  "sd.ads.faq4.q": { en: "Can you help improve landing pages too?", es: "\u00bfTambi\u00e9n pueden ayudar a mejorar las landing pages?", fr: "Pouvez-vous aussi am\u00e9liorer les pages de destination\u00a0?" },
  "sd.ads.faq4.a": { en: "Yes. We can optimize current landing pages or guide dedicated builds to improve conversion rates.", es: "Sí. Podemos optimizar landing pages actuales o guiar construcciones dedicadas para mejorar la conversión.", fr: "Oui. Nous pouvons optimiser les pages actuelles ou guider des constructions dédiées pour améliorer la conversion." },
  "sd.ads.faq5.q": { en: "What if I've never run ads before?", es: "¿Qué pasa si nunca he hecho anuncios antes?", fr: "Et si je n'ai jamais fait de publicité avant\u00a0?" },
  "sd.ads.faq5.a": { en: "That's actually great. It means we start with a clean slate, no bad habits to undo, no wasted budget to account for. We'll walk you through everything and build campaigns from scratch based on what actually works for your industry.", es: "Eso en realidad es genial. Significa que empezamos de cero, sin malos hábitos que corregir, sin presupuesto desperdiciado. Te guiamos en todo y construimos campañas desde cero basadas en lo que realmente funciona en tu industria.", fr: "C'est en fait super. Ça veut dire qu'on part de zéro, pas de mauvaises habitudes à corriger, pas de budget gaspillé. On vous guide à travers tout et on construit des campagnes à partir de rien basées sur ce qui marche vraiment dans votre industrie." },
  "sd.ads.faq6.q": { en: "How do you measure if ads are working?", es: "¿Cómo miden si los anuncios están funcionando?", fr: "Comment mesurez-vous si les pubs fonctionnent\u00a0?" },
  "sd.ads.faq6.a": { en: "We track real business outcomes, not vanity metrics. That means conversions, cost per lead, return on ad spend, and actual revenue generated. You'll get clear reporting that shows exactly where your money is going and what it's bringing back.", es: "Rastreamos resultados reales del negocio, no métricas de vanidad. Eso significa conversiones, costo por lead, retorno de inversión publicitaria e ingresos reales generados. Recibirás reportes claros que muestran exactamente a dónde va tu dinero y qué trae de vuelta.", fr: "On suit les résultats business réels, pas les métriques de vanité. Ça veut dire conversions, coût par lead, retour sur investissement publicitaire et revenus réels générés. Vous aurez des rapports clairs qui montrent exactement où va votre argent et ce qu'il rapporte." },

