  "sd.social.faq1.q": { en: "Which platforms do you support?", es: "\u00bfQu\u00e9 plataformas soportan?", fr: "Quelles plateformes supportez-vous\u00a0?" },
  "sd.social.faq1.a": { en: "We support the channels most relevant to your audience, commonly Instagram, Facebook, LinkedIn, TikTok, and YouTube Shorts.", es: "Soportamos los canales m\u00e1s relevantes para tu audiencia: Instagram, Facebook, LinkedIn, TikTok y YouTube Shorts.", fr: "Nous supportons les canaux les plus pertinents pour votre audience\u00a0: Instagram, Facebook, LinkedIn, TikTok et YouTube Shorts." },
  "sd.social.faq2.q": { en: "Do you create video content as part of this?", es: "\u00bfCrean contenido de video como parte de esto?", fr: "Cr\u00e9ez-vous du contenu vid\u00e9o dans ce cadre\u00a0?" },
  "sd.social.faq2.a": { en: "Yes. We can include short-form video production and combine it with our studio/video services when needed.", es: "S\u00ed. Podemos incluir producci\u00f3n de video corto y combinarlo con nuestros servicios de estudio/video.", fr: "Oui. Nous pouvons inclure la production de vid\u00e9os courtes et la combiner avec nos services studio/vid\u00e9o." },
  "sd.social.faq3.q": { en: "Do you handle comments and DMs?", es: "\u00bfManejan comentarios y mensajes directos?", fr: "G\u00e9rez-vous les commentaires et messages priv\u00e9s\u00a0?" },
  "sd.social.faq3.a": { en: "Yes, based on your plan scope. We can define response workflows and escalation paths for your team.", es: "S\u00ed, seg\u00fan el alcance de tu plan. Podemos definir flujos de respuesta y escalamiento para tu equipo.", fr: "Oui, selon la port\u00e9e de votre plan. Nous pouvons d\u00e9finir des flux de r\u00e9ponse et des chemins d\u2019escalade." },
  "sd.social.faq4.q": { en: "How do you measure social media success?", es: "\u00bfC\u00f3mo miden el \u00e9xito en redes sociales?", fr: "Comment mesurez-vous le succ\u00e8s sur les r\u00e9seaux sociaux\u00a0?" },
  "sd.social.faq4.a": { en: "We track engagement quality, audience relevance, traffic signals, and campaign-specific conversion behavior.", es: "Rastreamos calidad de engagement, relevancia de audiencia, se\u00f1ales de tr\u00e1fico y conversiones espec\u00edficas de campa\u00f1a.", fr: "Nous suivons la qualit\u00e9 de l\u2019engagement, la pertinence de l\u2019audience, les signaux de trafic et les conversions de campagne." },

