  "sd.email.d1.i2": { en: "Welcome and nurture automation sequences", es: "Secuencias de automatizaci\u00f3n de bienvenida y nutrici\u00f3n", fr: "S\u00e9quences d\u2019automatisation d\u2019accueil et de maturation" },
