  "sd.email.d1.i4": { en: "Deliverability and platform configuration checks", es: "Verificaciones de entregabilidad y configuraci\u00f3n de plataforma", fr: "V\u00e9rifications de d\u00e9livrabilit\u00e9 et configuration de plateforme" },
  "sd.email.d2.title": { en: "Campaign Operations", es: "Operaciones de Campa\u00f1a", fr: "Op\u00e9rations de campagne" },
  "sd.email.d2.desc": { en: "A repeatable monthly campaign cadence with ongoing optimization.", es: "Una cadencia de campa\u00f1a mensual repetible con optimizaci\u00f3n continua.", fr: "Une cadence de campagne mensuelle reproductible avec optimisation continue." },
  "sd.email.d2.i1": { en: "Monthly campaign planning and deployment", es: "Planificaci\u00f3n y despliegue de campa\u00f1as mensuales", fr: "Planification et d\u00e9ploiement de campagnes mensuelles" },
  "sd.email.d2.i2": { en: "Subject line and copy testing", es: "Pruebas de l\u00edneas de asunto y redacci\u00f3n", fr: "Tests de lignes d\u2019objet et de r\u00e9daction" },
  "sd.email.d2.i3": { en: "Performance monitoring and improvements", es: "Monitoreo de rendimiento y mejoras", fr: "Suivi des performances et am\u00e9liorations" },
  "sd.email.d2.i4": { en: "Monthly reporting with next actions", es: "Reportes mensuales con pr\u00f3ximas acciones", fr: "Rapports mensuels avec prochaines actions" },
  "sd.email.p1.step": { en: "Audience & Offer Mapping", es: "Mapeo de Audiencia y Oferta", fr: "Cartographie audience et offre" },
  "sd.email.p1.desc": { en: "We map key segments and align messaging to each stage of your customer journey.", es: "Mapeamos segmentos clave y alineamos mensajes a cada etapa del recorrido del cliente.", fr: "Nous cartographions les segments cl\u00e9s et alignons les messages \u00e0 chaque \u00e9tape du parcours client." },
  "sd.email.p2.step": { en: "Flow Buildout", es: "Construcci\u00f3n de Flujos", fr: "Construction des flux" },
  "sd.email.p2.desc": { en: "We implement lifecycle automations that support lead nurture and retention goals.", es: "Implementamos automatizaciones de ciclo de vida que apoyan nutrici\u00f3n de leads y retenci\u00f3n.", fr: "Nous impl\u00e9mentons des automatisations de cycle de vie qui soutiennent la maturation et la r\u00e9tention." },
  "sd.email.p3.step": { en: "Campaign Cadence", es: "Cadencia de Campa\u00f1a", fr: "Cadence de campagne" },
  "sd.email.p3.desc": { en: "We execute regular campaigns tied to offers, launches, and seasonal opportunities.", es: "Ejecutamos campa\u00f1as regulares ligadas a ofertas, lanzamientos y oportunidades estacionales.", fr: "Nous ex\u00e9cutons des campagnes r\u00e9guli\u00e8res li\u00e9es aux offres, lancements et opportunit\u00e9s saisonni\u00e8res." },
  "sd.email.p4.step": { en: "Testing & Optimization", es: "Pruebas y Optimizaci\u00f3n", fr: "Tests et optimisation" },
  "sd.email.p4.desc": { en: "We optimize subject lines, messaging, and segmentation based on real performance data.", es: "Optimizamos l\u00edneas de asunto, mensajes y segmentaci\u00f3n basados en datos de rendimiento reales.", fr: "Nous optimisons les lignes d\u2019objet, messages et segmentation \u00e0 partir de donn\u00e9es de performance r\u00e9elles." },
  "sd.email.t1.name": { en: "Startup", es: "Inicial", fr: "Startup" },
  "sd.email.t1.price": { en: "Starting at $750/mo", es: "Desde $750/mes", fr: "\u00c0 partir de 750\u00a0$/mois" },
  "sd.email.t1.desc": { en: "Best for foundational lifecycle setup", es: "Ideal para configuraci\u00f3n de ciclo de vida b\u00e1sica", fr: "Id\u00e9al pour la configuration de cycle de vie de base" },
  "sd.email.t1.f1": { en: "Core automation flow setup", es: "Configuraci\u00f3n de flujo de automatizaci\u00f3n b\u00e1sico", fr: "Configuration de flux d\u2019automatisation de base" },
  "sd.email.t1.f2": { en: "Monthly campaign support", es: "Soporte de campa\u00f1a mensual", fr: "Support de campagne mensuel" },
  "sd.email.t1.f3": { en: "Basic segmentation structure", es: "Estructura de segmentaci\u00f3n b\u00e1sica", fr: "Structure de segmentation de base" },
  "sd.email.t1.f4": { en: "Performance dashboard reporting", es: "Reportes de dashboard de rendimiento", fr: "Rapports de tableau de bord de performance" },
  "sd.email.t2.name": { en: "Growth", es: "Crecimiento", fr: "Croissance" },
  "sd.email.t2.price": { en: "Starting at $1,500/mo", es: "Desde $1,500/mes", fr: "\u00c0 partir de 1\u00a0500\u00a0$/mois" },
  "sd.email.t2.desc": { en: "Best for active lead and customer nurturing", es: "Ideal para nutrici\u00f3n activa de leads y clientes", fr: "Id\u00e9al pour la maturation active de leads et clients" },
  "sd.email.t2.f1": { en: "Expanded automation map", es: "Mapa de automatizaci\u00f3n expandido", fr: "Carte d\u2019automatisation \u00e9largie" },
  "sd.email.t2.f2": { en: "Increased campaign frequency", es: "Mayor frecuencia de campa\u00f1as", fr: "Fr\u00e9quence de campagnes accrue" },
