  "sd.email.t3.name": { en: "Scale", es: "Escala", fr: "\u00c9chelle" },
  "sd.email.t3.price": { en: "Starting at $3,000/mo", es: "Desde $3,000/mes", fr: "\u00c0 partir de 3\u00a0000\u00a0$/mois" },
  "sd.email.t3.desc": { en: "Best for high-volume and multi-offer brands", es: "Ideal para marcas de alto volumen y m\u00faltiples ofertas", fr: "Id\u00e9al pour les marques \u00e0 haut volume et offres multiples" },
  "sd.email.t3.f1": { en: "Advanced segmentation architecture", es: "Arquitectura de segmentaci\u00f3n avanzada", fr: "Architecture de segmentation avanc\u00e9e" },
  "sd.email.t3.f2": { en: "Complex flow build and refinement", es: "Construcci\u00f3n y refinamiento de flujos complejos", fr: "Construction et affinage de flux complexes" },
  "sd.email.t3.f3": { en: "Cross-channel automation support", es: "Soporte de automatizaci\u00f3n multicanal", fr: "Support d\u2019automatisation multi-canaux" },
  "sd.email.t3.f4": { en: "Priority optimization cycles", es: "Ciclos de optimizaci\u00f3n prioritarios", fr: "Cycles d\u2019optimisation prioritaires" },
  "sd.email.faq1.q": { en: "Which email platforms do you support?", es: "\u00bfQu\u00e9 plataformas de email soportan?", fr: "Quelles plateformes email supportez-vous\u00a0?" },
  "sd.email.faq1.a": { en: "We support major platforms like Klaviyo, Mailchimp, HubSpot, ActiveCampaign, and similar systems.", es: "Soportamos plataformas como Klaviyo, Mailchimp, HubSpot, ActiveCampaign y sistemas similares.", fr: "Nous supportons les principales plateformes comme Klaviyo, Mailchimp, HubSpot, ActiveCampaign et similaires." },
  "sd.email.faq2.q": { en: "Do you handle strategy and copywriting?", es: "\u00bfManejan estrategia y redacci\u00f3n?", fr: "G\u00e9rez-vous la strat\u00e9gie et la r\u00e9daction\u00a0?" },
  "sd.email.faq2.a": { en: "Yes. We handle lifecycle strategy, campaign planning, and copywriting aligned to your brand voice.", es: "S\u00ed. Manejamos estrategia de ciclo de vida, planificaci\u00f3n de campa\u00f1as y redacci\u00f3n alineada a tu voz de marca.", fr: "Oui. Nous g\u00e9rons la strat\u00e9gie de cycle de vie, la planification et la r\u00e9daction align\u00e9e sur votre voix de marque." },
  "sd.email.faq3.q": { en: "Can you improve deliverability?", es: "\u00bfPueden mejorar la entregabilidad?", fr: "Pouvez-vous am\u00e9liorer la d\u00e9livrabilit\u00e9\u00a0?" },
  "sd.email.faq3.a": { en: "Yes. We review list health, domain setup, and sending practices to improve inbox placement.", es: "S\u00ed. Revisamos la salud de la lista, configuraci\u00f3n de dominio y pr\u00e1cticas de env\u00edo para mejorar la entregabilidad.", fr: "Oui. Nous r\u00e9visons la sant\u00e9 de la liste, la configuration du domaine et les pratiques d\u2019envoi pour am\u00e9liorer le placement en bo\u00eete." },
  "sd.email.faq4.q": { en: "How often should campaigns be sent?", es: "\u00bfCon qu\u00e9 frecuencia deben enviarse las campa\u00f1as?", fr: "\u00c0 quelle fr\u00e9quence envoyer les campagnes\u00a0?" },
  "sd.email.faq4.a": { en: "Cadence depends on audience behavior and offer complexity. We create a sustainable rhythm and optimize over time.", es: "La cadencia depende del comportamiento de la audiencia y la complejidad de la oferta. Creamos un ritmo sostenible y optimizamos.", fr: "La cadence dépend du comportement de l'audience et de la complexité de l'offre. Nous créons un rythme durable et optimisons." },
  "sd.email.faq5.q": { en: "Can you work with whatever platform we're already using?", es: "¿Pueden trabajar con la plataforma que ya usamos?", fr: "Pouvez-vous travailler avec la plateforme qu'on utilise déjà\u00a0?" },
  "sd.email.faq5.a": { en: "Almost certainly. We work with Klaviyo, Mailchimp, HubSpot, ActiveCampaign, ConvertKit, Constant Contact, and most other major email platforms. If you're on something else, just ask. Odds are we've worked with it before.", es: "Casi seguro. Trabajamos con Klaviyo, Mailchimp, HubSpot, ActiveCampaign, ConvertKit, Constant Contact y la mayoría de las plataformas principales de email. Si usas otra cosa, solo pregunta. Lo más probable es que ya hayamos trabajado con ella.", fr: "Presque certainement. Nous travaillons avec Klaviyo, Mailchimp, HubSpot, ActiveCampaign, ConvertKit, Constant Contact et la plupart des autres grandes plateformes email. Si vous utilisez autre chose, demandez nous. Il y a de bonnes chances qu'on l'ait déjà utilisée." },

