  "sd.aiDev.name": { en: "AI Development & Automation", es: "Desarrollo de IA y Automatizaci\u00f3n", fr: "D\u00e9veloppement IA et automatisation" },
  "sd.aiDev.headline": { en: "Practical AI Workflows That Save Time and Improve Output", es: "Flujos de trabajo de IA pr\u00e1cticos que ahorran tiempo y mejoran resultados", fr: "Flux de travail IA pratiques qui font gagner du temps et am\u00e9liorent les r\u00e9sultats" },
  "sd.aiDev.desc": { en: "We design and implement AI-powered systems that remove repetitive work, tighten quality control, and help your team execute faster.", es: "Dise\u00f1amos e implementamos sistemas potenciados por IA que eliminan trabajo repetitivo, mejoran el control de calidad y ayudan a tu equipo a ejecutar m\u00e1s r\u00e1pido.", fr: "Nous concevons et impl\u00e9mentons des syst\u00e8mes aliment\u00e9s par l\u2019IA qui \u00e9liminent le travail r\u00e9p\u00e9titif, renforcent le contr\u00f4le qualit\u00e9 et aident votre \u00e9quipe \u00e0 ex\u00e9cuter plus vite." },
  "sd.aiDev.h1": { en: "Workflow Audits + Automation Mapping", es: "Auditor\u00edas de Flujo + Mapeo de Automatizaci\u00f3n", fr: "Audits de flux + cartographie d\u2019automatisation" },
  "sd.aiDev.h2": { en: "Prompt and Process Architecture", es: "Arquitectura de Prompts y Procesos", fr: "Architecture de prompts et processus" },
  "sd.aiDev.h3": { en: "Team Enablement and Optimization", es: "Habilitaci\u00f3n y Optimizaci\u00f3n de Equipo", fr: "Habilitation et optimisation d\u2019\u00e9quipe" },
  "sd.aiDev.o1": { en: "Reduced manual admin workload", es: "Carga de trabajo administrativo manual reducida", fr: "Charge de travail administratif manuelle r\u00e9duite" },
  "sd.aiDev.o2": { en: "Faster campaign and content execution", es: "Ejecuci\u00f3n de campa\u00f1as y contenido m\u00e1s r\u00e1pida", fr: "Ex\u00e9cution plus rapide des campagnes et du contenu" },
  "sd.aiDev.o3": { en: "More consistent output quality", es: "Calidad de producci\u00f3n m\u00e1s consistente", fr: "Qualit\u00e9 de production plus coh\u00e9rente" },
  "sd.aiDev.o4": { en: "Clearer reporting and delivery workflows", es: "Flujos de reporte y entrega m\u00e1s claros", fr: "Flux de rapports et de livraison plus clairs" },
  "sd.aiDev.o5": { en: "Scalable operations across team members", es: "Operaciones escalables entre miembros del equipo", fr: "Op\u00e9rations \u00e9volutives entre les membres de l\u2019\u00e9quipe" },
  "sd.aiDev.o6": { en: "Higher productivity on high-value tasks", es: "Mayor productividad en tareas de alto valor", fr: "Productivit\u00e9 accrue sur les t\u00e2ches \u00e0 haute valeur" },
  "sd.aiDev.d1.title": { en: "System Design", es: "Dise\u00f1o de Sistemas", fr: "Conception de syst\u00e8mes" },
  "sd.aiDev.d1.desc": { en: "We map your current process and design AI automation around real bottlenecks.", es: "Mapeamos tu proceso actual y dise\u00f1amos automatizaci\u00f3n con IA alrededor de cuellos de botella reales.", fr: "Nous cartographions votre processus actuel et concevons l\u2019automatisation IA autour des vrais goulets d\u2019\u00e9tranglement." },
  "sd.aiDev.d1.i1": { en: "Current workflow audit", es: "Auditor\u00eda de flujo de trabajo actual", fr: "Audit du flux de travail actuel" },
  "sd.aiDev.d1.i2": { en: "Automation opportunity map", es: "Mapa de oportunidades de automatizaci\u00f3n", fr: "Cartographie des opportunit\u00e9s d\u2019automatisation" },
  "sd.aiDev.d1.i3": { en: "Prompt and process architecture", es: "Arquitectura de prompts y procesos", fr: "Architecture de prompts et processus" },
  "sd.aiDev.d1.i4": { en: "Tool stack and integration recommendations", es: "Recomendaciones de herramientas e integraciones", fr: "Recommandations d\u2019outils et d\u2019int\u00e9grations" },
  "sd.aiDev.d2.title": { en: "Implementation Support", es: "Soporte de Implementaci\u00f3n", fr: "Support d\u2019impl\u00e9mentation" },
  "sd.aiDev.d2.desc": { en: "We deploy and tune your systems so they are usable by the team from day one.", es: "Desplegamos y ajustamos tus sistemas para que el equipo los use desde el d\u00eda uno.", fr: "Nous d\u00e9ployons et ajustons vos syst\u00e8mes pour qu\u2019ils soient utilisables par l\u2019\u00e9quipe d\u00e8s le premier jour." },
  "sd.aiDev.d2.i1": { en: "Automation build and deployment", es: "Construcci\u00f3n y despliegue de automatizaci\u00f3n", fr: "Construction et d\u00e9ploiement d\u2019automatisation" },
