  "sd.aiDev.d2.i3": { en: "Team handoff documentation", es: "Documentaci\u00f3n de transferencia al equipo", fr: "Documentation de transfert \u00e0 l\u2019\u00e9quipe" },
  "sd.aiDev.d2.i4": { en: "Iteration and optimization support", es: "Soporte de iteraci\u00f3n y optimizaci\u00f3n", fr: "Support d\u2019it\u00e9ration et d\u2019optimisation" },
  "sd.aiDev.p1.step": { en: "Audit Current Workflow", es: "Auditar Flujo Actual", fr: "Auditer le flux actuel" },
  "sd.aiDev.p1.desc": { en: "We identify repetitive bottlenecks, quality issues, and opportunities for AI leverage.", es: "Identificamos cuellos de botella repetitivos, problemas de calidad y oportunidades para aprovechar la IA.", fr: "Nous identifions les goulets r\u00e9p\u00e9titifs, les probl\u00e8mes de qualit\u00e9 et les opportunit\u00e9s de levier IA." },
