  "sd.aiDev.p2.desc": { en: "We define the right prompts, logic, and tools for your team and objectives.", es: "Definimos los prompts, l\u00f3gica y herramientas correctas para tu equipo y objetivos.", fr: "Nous d\u00e9finissons les bons prompts, la logique et les outils pour votre \u00e9quipe et vos objectifs." },
  "sd.aiDev.p3.step": { en: "Build & Launch", es: "Construir y Lanzar", fr: "Construire et lancer" },
  "sd.aiDev.p3.desc": { en: "We implement automations, test quality, and deploy with clear usage guidelines.", es: "Implementamos automatizaciones, probamos calidad y desplegamos con gu\u00edas de uso claras.", fr: "Nous impl\u00e9mentons les automatisations, testons la qualit\u00e9 et d\u00e9ployons avec des guides d\u2019utilisation clairs." },
  "sd.aiDev.p4.step": { en: "Train & Improve", es: "Capacitar y Mejorar", fr: "Former et am\u00e9liorer" },
  "sd.aiDev.p4.desc": { en: "We train your team and optimize workflows based on usage and performance data.", es: "Capacitamos a tu equipo y optimizamos flujos seg\u00fan datos de uso y rendimiento.", fr: "Nous formons votre \u00e9quipe et optimisons les flux \u00e0 partir des donn\u00e9es d\u2019utilisation et de performance." },
