  "sd.aiDev.t2.desc": { en: "Expanded AI operations system", es: "Sistema de operaciones de IA expandido", fr: "Syst\u00e8me d\u2019op\u00e9rations IA \u00e9largi" },
  "sd.aiDev.t2.f1": { en: "Multi-workflow automation support", es: "Soporte de automatizaci\u00f3n multi-flujo", fr: "Support d\u2019automatisation multi-flux" },
