  "sd.aiInt.name": { en: "Agent & AI Integration", es: "Agentes e Integraci\u00f3n de IA", fr: "Agents et int\u00e9gration IA" },
  "sd.aiInt.headline": { en: "Integrate AI Agents Into Real Business Workflows", es: "Integra agentes de IA en flujos de trabajo reales de negocio", fr: "Int\u00e9grez des agents IA dans de vrais flux de travail" },
  "sd.aiInt.desc": { en: "We help you deploy practical AI assistants for sales, content, support, and internal operations with clear guardrails and team adoption.", es: "Te ayudamos a desplegar asistentes de IA pr\u00e1cticos para ventas, contenido, soporte y operaciones internas con l\u00edmites claros y adopci\u00f3n del equipo.", fr: "Nous vous aidons \u00e0 d\u00e9ployer des assistants IA pratiques pour les ventes, le contenu, le support et les op\u00e9rations avec des garde-fous clairs et l\u2019adoption de l\u2019\u00e9quipe." },
  "sd.aiInt.h1": { en: "Use-Case and Workflow Mapping", es: "Mapeo de Casos de Uso y Flujos", fr: "Cartographie des cas d\u2019usage et flux" },
  "sd.aiInt.h2": { en: "Agent Setup + System Integration", es: "Configuraci\u00f3n de Agentes + Integraci\u00f3n", fr: "Configuration d\u2019agents + int\u00e9gration syst\u00e8me" },
  "sd.aiInt.h3": { en: "Governance, QA, and Team Enablement", es: "Gobernanza, QA y Habilitaci\u00f3n del Equipo", fr: "Gouvernance, QA et habilitation d\u2019\u00e9quipe" },
  "sd.aiInt.o1": { en: "Faster response and follow-up workflows", es: "Flujos de respuesta y seguimiento m\u00e1s r\u00e1pidos", fr: "Flux de r\u00e9ponse et de suivi plus rapides" },
  "sd.aiInt.o2": { en: "Better access to internal knowledge", es: "Mejor acceso al conocimiento interno", fr: "Meilleur acc\u00e8s aux connaissances internes" },
  "sd.aiInt.o3": { en: "Consistent team execution standards", es: "Est\u00e1ndares de ejecuci\u00f3n de equipo consistentes", fr: "Standards d\u2019ex\u00e9cution d\u2019\u00e9quipe coh\u00e9rents" },
  "sd.aiInt.o4": { en: "Reduced process bottlenecks", es: "Reducci\u00f3n de cuellos de botella en procesos", fr: "R\u00e9duction des goulets d\u2019\u00e9tranglement" },
  "sd.aiInt.o5": { en: "Improved cross-channel coordination", es: "Mejor coordinaci\u00f3n multicanal", fr: "Meilleure coordination multi-canaux" },
