  "sd.aiInt.d1.title": { en: "Integration Planning", es: "Planificaci\u00f3n de Integraci\u00f3n", fr: "Planification d\u2019int\u00e9gration" },
  "sd.aiInt.d1.desc": { en: "We define where AI agents should fit and how they should behave.", es: "Definimos d\u00f3nde deben encajar los agentes de IA y c\u00f3mo deben comportarse.", fr: "Nous d\u00e9finissons o\u00f9 les agents IA doivent s\u2019int\u00e9grer et comment ils doivent se comporter." },
