  "sd.aiInt.d1.i3": { en: "Data source and process alignment", es: "Alineaci\u00f3n de fuentes de datos y procesos", fr: "Alignement des sources de donn\u00e9es et processus" },
  "sd.aiInt.d1.i4": { en: "Risk and quality guardrails", es: "L\u00edmites de riesgo y calidad", fr: "Garde-fous de risque et qualit\u00e9" },
  "sd.aiInt.d2.title": { en: "Deployment & Adoption", es: "Despliegue y Adopci\u00f3n", fr: "D\u00e9ploiement et adoption" },
  "sd.aiInt.d2.desc": { en: "We launch assistants and make sure your team can use them confidently.", es: "Lanzamos asistentes y nos aseguramos de que tu equipo pueda usarlos con confianza.", fr: "Nous lan\u00e7ons les assistants et nous assurons que votre \u00e9quipe peut les utiliser en confiance." },
  "sd.aiInt.d2.i1": { en: "Agent setup and tool integration", es: "Configuraci\u00f3n de agentes e integraci\u00f3n de herramientas", fr: "Configuration d\u2019agents et int\u00e9gration d\u2019outils" },
  "sd.aiInt.d2.i2": { en: "Workflow testing and tuning", es: "Pruebas y ajuste de flujos de trabajo", fr: "Tests et ajustement des flux de travail" },
  "sd.aiInt.d2.i3": { en: "Team training and enablement", es: "Capacitaci\u00f3n y habilitaci\u00f3n del equipo", fr: "Formation et habilitation de l\u2019\u00e9quipe" },
  "sd.aiInt.d2.i4": { en: "Ongoing performance optimization", es: "Optimizaci\u00f3n continua de rendimiento", fr: "Optimisation continue des performances" },
  "sd.aiInt.p1.step": { en: "Define Use Cases", es: "Definir Casos de Uso", fr: "D\u00e9finir les cas d\u2019usage" },
  "sd.aiInt.p1.desc": { en: "We identify high-impact workflows where AI agents can reduce friction and save time.", es: "Identificamos flujos de alto impacto donde los agentes de IA pueden reducir fricci\u00f3n y ahorrar tiempo.", fr: "Nous identifions les flux \u00e0 fort impact o\u00f9 les agents IA peuvent r\u00e9duire les frictions et gagner du temps." },
  "sd.aiInt.p2.step": { en: "Design Agent Behavior", es: "Dise\u00f1ar Comportamiento del Agente", fr: "Concevoir le comportement de l\u2019agent" },
  "sd.aiInt.p2.desc": { en: "We structure prompts, data access, and output standards to keep responses reliable.", es: "Estructuramos prompts, acceso a datos y est\u00e1ndares de salida para mantener respuestas confiables.", fr: "Nous structurons les prompts, l\u2019acc\u00e8s aux donn\u00e9es et les standards de sortie pour des r\u00e9ponses fiables." },
  "sd.aiInt.p3.step": { en: "Integrate Into Systems", es: "Integrar en Sistemas", fr: "Int\u00e9grer dans les syst\u00e8mes" },
  "sd.aiInt.p3.desc": { en: "We connect agents to your workflows and tools with testing for quality and reliability.", es: "Conectamos agentes a tus flujos y herramientas con pruebas de calidad y confiabilidad.", fr: "Nous connectons les agents \u00e0 vos flux et outils avec des tests de qualit\u00e9 et fiabilit\u00e9." },
  "sd.aiInt.p4.step": { en: "Enable Team Adoption", es: "Habilitar Adopci\u00f3n del Equipo", fr: "Faciliter l\u2019adoption par l\u2019\u00e9quipe" },
  "sd.aiInt.p4.desc": { en: "We train your team, monitor outcomes, and iterate based on real-world usage.", es: "Capacitamos a tu equipo, monitoreamos resultados e iteramos seg\u00fan el uso real.", fr: "Nous formons votre \u00e9quipe, surveillons les r\u00e9sultats et it\u00e9rons selon l\u2019utilisation r\u00e9elle." },
