  "sd.aiInt.t1.f1": { en: "Use-case definition", es: "Definici\u00f3n de caso de uso", fr: "D\u00e9finition de cas d\u2019usage" },
  "sd.aiInt.t1.f2": { en: "Baseline agent setup and prompts", es: "Configuraci\u00f3n b\u00e1sica de agente y prompts", fr: "Configuration de base de l\u2019agent et prompts" },
  "sd.aiInt.t1.f3": { en: "Basic deployment support", es: "Soporte b\u00e1sico de despliegue", fr: "Support de d\u00e9ploiement de base" },
