  "sd.aiInt.t2.price": { en: "Starting at $1,500/mo", es: "Desde $1,500/mes", fr: "\u00c0 partir de 1\u00a0500\u00a0$/mois" },
  "sd.aiInt.t2.desc": { en: "Multi-use workflow integration support", es: "Soporte de integraci\u00f3n de flujos m\u00faltiples", fr: "Support d\u2019int\u00e9gration de flux multiples" },
  "sd.aiInt.t2.f1": { en: "Multiple agent workflows", es: "Flujos de trabajo de m\u00faltiples agentes", fr: "Flux de travail multi-agents" },
