  "sd.aiInt.t3.price": { en: "Starting at $3,000/mo", es: "Desde $3,000/mes", fr: "\u00c0 partir de 3\u00a0000\u00a0$/mois" },
  "sd.aiInt.t3.desc": { en: "Advanced cross-functional integration", es: "Integraci\u00f3n avanzada multifuncional", fr: "Int\u00e9gration avanc\u00e9e multifonctionnelle" },
  "sd.aiInt.t3.f1": { en: "Cross-team workflow integrations", es: "Integraciones de flujo multi-equipo", fr: "Int\u00e9grations de flux multi-\u00e9quipes" },
  "sd.aiInt.t3.f2": { en: "Custom governance standards", es: "Est\u00e1ndares de gobernanza personalizados", fr: "Standards de gouvernance personnalis\u00e9s" },
  "sd.aiInt.t3.f3": { en: "Advanced quality assurance", es: "Aseguramiento de calidad avanzado", fr: "Assurance qualit\u00e9 avanc\u00e9e" },
  "sd.aiInt.t3.f4": { en: "Priority support and iteration", es: "Soporte prioritario e iteraci\u00f3n", fr: "Support prioritaire et it\u00e9ration" },
  "sd.aiInt.faq1.q": { en: "What types of AI agents can you implement?", es: "\u00bfQu\u00e9 tipos de agentes de IA pueden implementar?", fr: "Quels types d\u2019agents IA pouvez-vous impl\u00e9menter\u00a0?" },
  "sd.aiInt.faq1.a": { en: "We support sales assistants, content assistants, SOP assistants, and workflow-specific agents tailored to your operations.", es: "Soportamos asistentes de ventas, contenido, SOPs y agentes espec\u00edficos de flujos adaptados a tus operaciones.", fr: "Nous supportons les assistants de vente, contenu, SOP et agents sp\u00e9cifiques aux flux adapt\u00e9s \u00e0 vos op\u00e9rations." },
  "sd.aiInt.faq2.q": { en: "How do you maintain quality and brand consistency?", es: "\u00bfC\u00f3mo mantienen la calidad y consistencia de marca?", fr: "Comment maintenez-vous la qualit\u00e9 et la coh\u00e9rence de marque\u00a0?" },
  "sd.aiInt.faq2.a": { en: "We define behavior rules, prompts, and review checkpoints so outputs stay aligned to your standards.", es: "Definimos reglas de comportamiento, prompts y puntos de revisi\u00f3n para que las salidas se mantengan alineadas a tus est\u00e1ndares.", fr: "Nous d\u00e9finissons des r\u00e8gles de comportement, prompts et points de contr\u00f4le pour que les sorties restent align\u00e9es sur vos standards." },
  "sd.aiInt.faq3.q": { en: "Can we start small and expand later?", es: "\u00bfPodemos empezar peque\u00f1o y expandir despu\u00e9s?", fr: "Pouvons-nous commencer petit et \u00e9tendre ensuite\u00a0?" },
  "sd.aiInt.faq3.a": { en: "Yes. We typically start with one high-impact use case and expand after proving operational value.", es: "S\u00ed. T\u00edpicamente comenzamos con un caso de uso de alto impacto y expandimos despu\u00e9s de demostrar valor operacional.", fr: "Oui. Nous commen\u00e7ons g\u00e9n\u00e9ralement par un cas d\u2019usage \u00e0 fort impact et \u00e9tendons apr\u00e8s avoir prouv\u00e9 la valeur op\u00e9rationnelle." },
  "sd.aiInt.faq4.q": { en: "Will this replace our team?", es: "\u00bfEsto reemplazar\u00e1 a nuestro equipo?", fr: "Cela remplacera-t-il notre \u00e9quipe\u00a0?" },
  "sd.aiInt.faq4.a": { en: "No. The goal is to amplify your team by automating repetitive tasks and speeding up execution quality.", es: "No. El objetivo es amplificar a tu equipo automatizando tareas repetitivas y acelerando la calidad de ejecuci\u00f3n.", fr: "Non. L\u2019objectif est d\u2019amplifier votre \u00e9quipe en automatisant les t\u00e2ches r\u00e9p\u00e9titives et en acc\u00e9l\u00e9rant la qualit\u00e9 d\u2019ex\u00e9cution." },

