  "sd.video.t2.f3": { en: "Editing and revision support", es: "Soporte de edici\u00f3n y revisi\u00f3n", fr: "Support d\u2019\u00e9dition et de r\u00e9vision" },
  "sd.video.t2.f4": { en: "Cross-channel format variants", es: "Variantes de formato multicanal", fr: "Variantes de format multi-canaux" },
  "sd.video.t3.name": { en: "Scale", es: "Escala", fr: "\u00c9chelle" },
  "sd.video.t3.price": { en: "Starting at $3,000/mo", es: "Desde $3,000/mes", fr: "\u00c0 partir de 3\u00a0000\u00a0$/mois" },
  "sd.video.t3.desc": { en: "Best for high-frequency production needs", es: "Ideal para necesidades de producci\u00f3n de alta frecuencia", fr: "Id\u00e9al pour les besoins de production haute fr\u00e9quence" },
  "sd.video.t3.f1": { en: "Monthly content planning", es: "Planificaci\u00f3n de contenido mensual", fr: "Planification de contenu mensuel" },
  "sd.video.t3.f2": { en: "Recurring production cadence", es: "Cadencia de producci\u00f3n recurrente", fr: "Cadence de production r\u00e9currente" },
  "sd.video.t3.f3": { en: "Advanced post-production workflow", es: "Flujo de postproducci\u00f3n avanzado", fr: "Flux de post-production avanc\u00e9" },
  "sd.video.t3.f4": { en: "Priority turnaround support", es: "Soporte de entrega prioritaria", fr: "Support de d\u00e9lai prioritaire" },
  "sd.video.faq1.q": { en: "Do you handle scripting and creative direction?", es: "\u00bfManejan gui\u00f3n y direcci\u00f3n creativa?", fr: "G\u00e9rez-vous le sc\u00e9nario et la direction cr\u00e9ative\u00a0?" },
  "sd.video.faq1.a": { en: "Yes. We support concept development, scripting direction, and production planning end-to-end.", es: "S\u00ed. Apoyamos desarrollo de concepto, direcci\u00f3n de gui\u00f3n y planificaci\u00f3n de producci\u00f3n de principio a fin.", fr: "Oui. Nous supportons le d\u00e9veloppement de concept, la direction de sc\u00e9nario et la planification de production de bout en bout." },
  "sd.video.faq2.q": { en: "Can one shoot produce multiple assets?", es: "\u00bfPuede una grabaci\u00f3n producir m\u00faltiples activos?", fr: "Un tournage peut-il produire plusieurs contenus\u00a0?" },
  "sd.video.faq2.a": { en: "Yes. We routinely repurpose one shoot into long-form, short-form, and platform-specific content variants.", es: "S\u00ed. Reutilizamos rutinariamente una grabaci\u00f3n en variantes de formato largo, corto y espec\u00edficas por plataforma.", fr: "Oui. Nous r\u00e9utilisons r\u00e9guli\u00e8rement un tournage en variantes format long, court et sp\u00e9cifiques par plateforme." },
  "sd.video.faq3.q": { en: "Do you only film in your studio?", es: "\u00bfSolo graban en su estudio?", fr: "Filmez-vous uniquement dans votre studio\u00a0?" },
  "sd.video.faq3.a": { en: "No. We support both studio and on-location productions based on the project goals.", es: "No. Soportamos producciones tanto en estudio como en locaci\u00f3n seg\u00fan los objetivos del proyecto.", fr: "Non. Nous supportons les productions en studio et sur site selon les objectifs du projet." },
  "sd.video.faq4.q": { en: "What is typical turnaround time?", es: "\u00bfCu\u00e1l es el tiempo de entrega t\u00edpico?", fr: "Quel est le d\u00e9lai de livraison typique\u00a0?" },
  "sd.video.faq4.a": { en: "Depending on scope and revision cycles, standard projects are often delivered in about 1-3 weeks.", es: "Dependiendo del alcance y ciclos de revisi\u00f3n, los proyectos est\u00e1ndar se entregan generalmente en 1-3 semanas.", fr: "Selon la port\u00e9e et les cycles de r\u00e9vision, les projets standards sont g\u00e9n\u00e9ralement livr\u00e9s en 1-3 semaines." },

