  "roi.timeline.title": { en: "Expected Results Timeline", es: "Cronograma de Resultados Esperados", fr: "Calendrier des Résultats Attendus" },
  "roi.timeline.noSpend": { en: "Enter your current marketing spend above to see how long it will take to reach your goals.", es: "Ingresa tu gasto actual en marketing arriba para ver cuánto tiempo tomará alcanzar tus metas.", fr: "Entrez votre budget marketing actuel ci-dessus pour voir combien de temps il faudra pour atteindre vos objectifs." },
  "roi.timeline.veryLong": { en: "At your current spend level, you're significantly under budget. Results will come, but very slowly. Most of your budget is going to maintenance rather than growth. Expect slow, gradual progress with this level of investment.", es: "Con tu nivel de gasto actual, estás significativamente por debajo del presupuesto. Los resultados llegarán, pero muy lentamente. La mayoría de tu presupuesto va a mantenimiento en vez de crecimiento.", fr: "À votre niveau de dépenses actuel, vous êtes significativement sous le budget. Les résultats viendront, mais très lentement. La majorité de votre budget va à la maintenance plutôt qu'à la croissance." },
  "roi.timeline.slow": { en: "Your budget is getting there but still below where it needs to be. You'll see some momentum, but competitors spending at full capacity will outpace you. Growth will happen, just on a longer timeline.", es: "Tu presupuesto está avanzando pero aún debajo de donde necesita estar. Verás algo de impulso, pero competidores gastando a capacidad completa te superarán. El crecimiento pasará, solo en un plazo más largo.", fr: "Votre budget progresse mais reste en dessous de ce qu'il faut. Vous verrez un certain élan, mais les concurrents qui dépensent à pleine capacité vous dépasseront." },
  "roi.timeline.moderate": { en: "You're close to the right budget level. Results will start showing within a few months. With some optimization, you could see meaningful momentum building by month 5 or 6.", es: "Estás cerca del nivel de presupuesto correcto. Los resultados comenzarán a mostrarse en unos meses. Con algo de optimización, podrías ver impulso significativo para el mes 5 o 6.", fr: "Vous êtes proche du bon niveau de budget. Les résultats commenceront à apparaître dans quelques mois. Avec un peu d'optimisation, vous pourriez voir un élan significatif vers le mois 5 ou 6." },
  "roi.timeline.onTrack": { en: "Your budget is right where it should be. Expect to start seeing early wins in months 2 to 3, with compounding results by month 4 to 6. This is the sweet spot for sustainable growth.", es: "Tu presupuesto está justo donde debe estar. Espera ver primeras victorias en los meses 2 a 3, con resultados compuestos para el mes 4 a 6. Este es el punto ideal para crecimiento sostenible.", fr: "Votre budget est exactement là où il devrait être. Attendez-vous à voir des premiers résultats aux mois 2 à 3, avec des résultats composés vers le mois 4 à 6." },
  "roi.timeline.accelerated": { en: "You're investing above the baseline, which means faster results. You'll see momentum building quickly and should hit your targets ahead of schedule. Smart move.", es: "Estás invirtiendo por encima de la base, lo que significa resultados más rápidos. Verás impulso construyéndose rápidamente y deberías alcanzar tus metas antes de lo programado.", fr: "Vous investissez au-dessus de la base, ce qui signifie des résultats plus rapides. Vous verrez l'élan se construire rapidement et devriez atteindre vos objectifs en avance." },
  "roi.timeline.fast": { en: "Aggressive investment. You'll see results fast. With this level of spend, expect rapid customer acquisition and significant market presence gains within the first few months.", es: "Inversión agresiva. Verás resultados rápido. Con este nivel de gasto, espera adquisición rápida de clientes y ganancias significativas en presencia de mercado en los primeros meses.", fr: "Investissement agressif. Vous verrez des résultats rapidement. Avec ce niveau de dépenses, attendez-vous à une acquisition rapide de clients et des gains significatifs de présence sur le marché." },
  "roi.timeline.speedUp": { en: "Want faster results? Increasing your budget closer to the recommended amount will significantly shorten your timeline.", es: "¿Quieres resultados más rápidos? Aumentar tu presupuesto más cerca de la cantidad recomendada acortará significativamente tu cronograma.", fr: "Vous voulez des résultats plus rapides? Augmenter votre budget plus près du montant recommandé raccourcira significativement votre calendrier." },

